package org.apache.commons.lang3.builder;

/**
 * Assists in implementing {@link Diffable#diff(Object)} methods.
 *
 * This class now delegates core state and append implementations to {@link DiffBuilderCore}.
 *
 * @param <T> type of the left and right object.
 * @since 3.3
 */
public class DiffBuilder<T> implements Builder<DiffResult<T>> {

    /**
     * Two-argument format string used by default.
     */
    public static final String TO_STRING_FORMAT = "%s differs from %s";

    /**
     * Underlying core implementation that does the heavy lifting.
     */
    private final DiffBuilderCore<T, ?> core;

    /**
     * Two-argument Builder for convenient construction of configured DiffBuilder instances.
     *
     * @param <T> type of the left and right object.
     * @since 3.15.0
     */
    public static final class Builder<T> {

        private T left;
        private T right;
        private ToStringStyle style;
        private boolean testObjectsEquals = true;
        private String toStringFormat = TO_STRING_FORMAT;

        /**
         * Constructs a new instance.
         */
        public Builder() {
            // empty
        }

        /**
         * Builds a new configured {@link DiffBuilder}.
         *
         * @return a new configured {@link DiffBuilder}.
         */
        public DiffBuilder<T> build() {
            // Create a core and wrap it in a facade DiffBuilder
            final DiffBuilderCore<T, ?> core = new DiffBuilderCore<>(left, right, style, testObjectsEquals, toStringFormat);
            return new DiffBuilder<>(core);
        }

        public Builder<T> setLeft(final T left) {
            this.left = left;
            return this;
        }

        public Builder<T> setRight(final T right) {
            this.right = right;
            return this;
        }

        public Builder<T> setStyle(final ToStringStyle style) {
            this.style = style != null ? style : ToStringStyle.DEFAULT_STYLE;
            return this;
        }

        public Builder<T> setTestObjectsEquals(final boolean testObjectsEquals) {
            this.testObjectsEquals = testObjectsEquals;
            return this;
        }

        public Builder<T> setToStringFormat(final String toStringFormat) {
            this.toStringFormat = toStringFormat != null ? toStringFormat : TO_STRING_FORMAT;
            return this;
        }
    }

    /**
     * Constructs a new {@link Builder}.
     *
     * @param <T> type of the left and right object.
     * @return a new {@link Builder}.
     * @since 3.15.0
     */
    public static <T> Builder<T> builder() {
        return new Builder<>();
    }

    /**
     * Deprecated constructor kept for compatibility.
     */
    @Deprecated
    public DiffBuilder(final T left, final T right, final ToStringStyle style) {
        this(left, right, style, true);
    }

    /**
     * Deprecated constructor kept for compatibility.
     */
    @Deprecated
    public DiffBuilder(final T left, final T right, final ToStringStyle style, final boolean testObjectsEquals) {
        this(left, right, style, testObjectsEquals, TO_STRING_FORMAT);
    }

    private DiffBuilder(final T left, final T right, final ToStringStyle style, final boolean testObjectsEquals, final String toStringFormat) {
        this.core = new DiffBuilderCore<>(left, right, style, testObjectsEquals, toStringFormat);
    }

    /**
     * Internal constructor used by Builder when a core instance is already created.
     */
    private DiffBuilder(final DiffBuilderCore<T, ?> core) {
        this.core = core;
    }

    // Delegate commonly used operations to the core and return this for chaining.

    public DiffBuilder<T> append(final String fieldName, final Object lhs, final Object rhs) {
        core.append(fieldName, lhs, rhs);
        return this;
    }

    public DiffBuilder<T> append(final String fieldName, final DiffResult<?> diffResult) {
        core.append(fieldName, diffResult);
        return this;
    }

    @Override
    public DiffResult<T> build() {
        return core.build();
    }

    public T getLeft() {
        return core.getLeft();
    }

    public T getRight() {
        return core.getRight();
    }

}
